INSERT INTO `trip_days` VALUES (14001,13001,1,'2026-07-17','1일차 일정','첫날은 북동쪽 해안선을 따라 바다 포인트를 연속으로 묶었습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14002,13001,2,'2026-07-18','2일차 일정','둘째 날은 숲과 성산권을 한 묶음으로 정리해 장거리 왕복을 줄였습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14003,13001,3,'2026-07-19','3일차 일정','마지막 날은 섭지코지와 표선권만 짧게 끊어 체크아웃 부담을 줄였습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14004,13002,1,'2026-07-24','1일차 일정','첫날은 강릉 시내와 주문진까지 한 방향으로 끌고 올라갑니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14005,13002,2,'2026-07-25','2일차 일정','둘째 날은 속초권 포인트만 묶어 도심 회전을 줄였습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14006,13003,1,'2026-07-31','1일차 일정','첫날은 해운대권에서 야경 포인트를 중심으로 묶었습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14007,13003,2,'2026-08-01','2일차 일정','둘째 날은 광안리에서 남포 쪽으로 내려가며 야경을 연결합니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14008,13004,1,'2026-08-07','1일차 일정','시내권 유적은 도보 전환이 쉬운 순서로 같은 날에 묶었습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14009,13004,2,'2026-08-08','2일차 일정','둘째 날은 불국사권과 보문단지를 묶어 차량 중심으로 이동합니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14010,13005,1,'2026-08-14','1일차 일정','첫날은 역 인근과 구도심을 묶어 도심 이동을 줄였습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14011,13005,2,'2026-08-15','2일차 일정','둘째 날은 돌산권을 묶어 케이블카와 전망대를 한 번에 정리합니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14012,13006,1,'2026-08-21','1일차 일정','성곽권 핵심 포인트만 짧게 끊어 야경 시간대에 맞춰 완성한 코스입니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14013,13007,1,'2026-08-28','1일차 일정','주차 이후 이동 반경을 좁게 잡아 먹거리와 사진 포인트를 묶었습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14014,13008,1,'2026-09-04','1일차 일정','첫날은 독일마을과 해안 전망대를 한 방향으로 묶었습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14015,13008,2,'2026-09-05','2일차 일정','둘째 날은 남쪽 해안선 포인트만 묶어 짧게 마무리했습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14016,13009,1,'2026-09-17','1일차 일정','첫날은 공항에서 비에이 남쪽 포인트만 짧게 묶었습니다.','2026-06-09 21:56:57','2026-06-09 21:56:57'),(14017,13009,2,'2026-09-18','2일차 일정','둘째 날은 비에이-후라노 사이 대형 풍경 포