-- community_routes
INSERT INTO `community_routes` VALUES (16001,13001,12001,'제주 동쪽 해안 드라이브 3일 플랜','동쪽 해안선을 따라 이동 거리를 한 방향으로 묶어 만든 제주 렌터카 루트입니다. 바다 포인트를 먼저 보고 카페와 산책 지점을 끼워 넣어 피로도를 낮췄습니다.',NULL,'coast',438,9,3,8,'published','2026-06-09 21:56:57','2026-06-09 21:56:57'),(16002,13002,12002,'강릉-속초 동해안 드라이브 2일 코스','동해안 북상 흐름에 맞춰 강릉에서 속초로 올라가는 차량 루트입니다. 왕복 없이 해안선 방향으로 이동해서 이동 스트레스를 줄였습니다.',NULL,'coast',362,8,3,7,'published','2026-06-09 21:56:57','2026-06-09 21:56:57'),(16003,13003,12003,'부산 해안 야경 드라이브 2일 코스','동선이 겹치지 않도록 해운대권과 남포권을 나눠 묶은 부산 차량 루트입니다. 야경 포인트는 저녁 시간대에 맞춰 후반부에 배치했습니다.',NULL,'coast',329,8,3,6,'published','2026-06-09 21:56:57','2026-06-09 21:56:57'),(16004,13004,12004,'경주 역사 유적 드라이브 2일 코스','황리단길과 시내 유적, 불국사권을 날짜별로 분리해 차량 회전을 줄인 경주 드라이브 루트입니다. 도보가 많은 구간은 같은 날 안에서만 묶었습니다.',NULL,'urban',276,7,3,5,'published','2026-06-09 21:56:57','2026-06-09 21:56:57'),(16005,13005,12005,'여수 밤바다 드라이브 2일 코스','오동도와 구도심, 돌산권을 날짜별로 나눠 야경 시간을 살린 여수 드라이브 코스입니다. 바다를 보면서도 차량 이동이 과하게 꼬이지 않도록 정리했습니다.',NULL,'coast',298,7,3,5,'published','2026-06-09 21:56:57','2026-06-09 21:56:57'),(16006,13006,12006,'수원 성곽 야경 드라이브 1일 코스','수원 화성권을 크게 돌지 않고 성곽-카페-시장-야경 순서로 묶은 1일 차량 루트입니다. 주차 후 짧게 걸을 구간만 남기도록 설계했습니다.',NULL,'urban',188,5,2,3,'published','2026-06-09 21:56:57','2026-06-09 21:56:57'),(16007,13007,12007,'전주 한옥 미식 드라이브 1일 코스','전주 한옥마을권에서 너무 멀리 벗어나지 않으면서 먹거리와 사진 포인트를 같이 담은 1일 차량 루트입니다. 주차 후 짧은 도보 중심으로 움직이기 좋게 정리했습니다.',NULL,'cafe',164,5,2,6,'published','2026-06-09 21:56:57','2026-06-09 21:56:57'),(16008,13008,12008,'남해 해안 드라이브 2일 코스','남해는 포인트 간 거리가 있어서 차량 이동 순서를 잘 짜는 게 중요한데, 서쪽과 남쪽 해안 포인트를 하루씩 나눠 배치한 루트입니다.',NULL,'coast',241,6,2,5,'published','2026-06-09 21:56:57','2026-06-09 21:56:57'),(16009,13009,12009,'홋카이도 비에이-후라노 드라이브 3일 플랜','비에이와 후라노는 포인트 사이 거리가 꽤 있어서 렌터카 기준 동선이 중요합니다. 푸른연못-비에이-후라노 축을 날짜별로 정리해 왕복을 줄였습니다.',NULL,'coast',421,9,3,8,'published','2026-06-09 21:56:57','2026-06-09 21:56:57'),(16010,13010,12010,'LA 해안 드라이브 2일 코스','LA는 이동 자체가 길어서 서쪽 해안권과 시내 전망권을 나눠 끊는 편이 훨씬 안정적입니다. 해안선과 시내 뷰 포인트를 날짜별로 분리한 차량 최적화 코스입니다.',NULL,'coast',462,10,3,17,'published','2026-06-09 21:56:57','2026-06-09 21:56:57');


