-- community_route_comments
INSERT INTO `community_route_comments` VALUES (32001,16001,2009,'공항에서 동쪽으로만 밀고 가는 방식이라 운전이 훨씬 편해 보여요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32002,16001,12002,'성산이랑 광치기를 같은 날로 묶은 게 실제로 움직이기 좋아 보입니다.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32003,16001,12003,'제주 초행이면 이 정도 구성이 제일 안정적일 것 같아요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32004,16002,2009,'강릉에서 속초로 올라가는 방향이라 되돌아가는 느낌이 없어서 좋아요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32005,16002,12001,'강문이랑 안목을 묶은 다음 주문진으로 빼는 게 꽤 깔끔하네요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32006,16002,12003,'속초 쪽은 둘째 날에만 모아둔 게 실제 운전 피로를 줄여줄 것 같아요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32007,16003,2009,'광안리랑 흰여울을 하루에 묶은 게 야경 루트로 정말 좋아 보이네요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32008,16003,12001,'해운대권을 하루 따로 뺀 덕분에 운전 피로가 덜할 것 같아요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32009,16003,12002,'달맞이길 넣은 타이밍이 부산 느낌 살리기 좋습니다.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32010,16004,2009,'시내 유적이랑 불국사권을 날짜로 나눈 게 정말 합리적이네요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32011,16004,12001,'경주는 걷다가 힘들어지는 경우가 많은데 차량 기준으로 잘 끊은 것 같아요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32012,16004,12002,'동궁과 월지를 저녁으로 둔 게 분위기상 제일 좋습니다.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32013,16005,2009,'여수는 밤 시간이 중요해서 돌산권을 따로 뺀 게 정말 좋네요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32014,16005,12001,'첫날 구도심, 둘째 날 돌산으로 나눈 게 시연용으로도 직관적이에요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32015,16005,12002,'케이블카 앞뒤 시간이 딱 적당해 보여서 그대로 따라가고 싶습니다.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32016,16006,2009,'행궁동은 주차 때문에 애매한데 이렇게 끊으니까 훨씬 따라가기 쉽겠네요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32017,16006,12001,'방화수류정을 마지막에 둔 이유가 명확해서 시연용으로도 좋아 보여요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32018,16007,2009,'전주는 주차 이후 동선이 꼬이기 쉬운데 이렇게 좁게 묶은 게 좋네요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32019,16007,12001,'먹거리랑 사진 포인트가 같이 있어서 하루 코스로 부담이 적어 보여요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32020,16008,2009,'남해는 방향 잘못 잡으면 운전이 길어지는데 서쪽/남쪽으로 나눈 게 좋습니다.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32021,16008,12001,'보리암을 첫날 핵심으로 빼둔 이유가 명확하네요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32022,16009,2009,'홋카이도는 렌터카 동선이 중요한데 날짜를 이렇게 나눈 게 정말 좋아 보여요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32023,16009,12001,'비에이랑 후라노를 억지로 하루에 안 넣어서 오히려 현실적입니다.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32024,16009,12002,'Ningle Terrace를 둘째 날 저녁으로 둔 게 감성도 챙기고 동선도 좋네요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32025,16010,2009,'LA는 하루에 너무 많이 넣으면 피곤한데 서쪽/시내로 나눈 게 좋네요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32026,16010,12001,'그리피스에서 말리부로 빠지는 흐름이 시연용으로도 꽤 임팩트 있어 보여요.','active','2026-06-09 21:56:57','2026-06-09 21:56:57'),(32027,16010,12002,'렌터카 여행 기준으로 실제 따라가기 쉬운 편이라 저장해두고 싶습니다.','active','2026-06-09 21:56:57','2026-06-09 21:56:57');


